using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class ToxicWordConfiguration : IEntityTypeConfiguration<ToxicWord>{public void Configure(EntityTypeBuilder<ToxicWord> builder){builder.ToTable("toxic_words");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("word_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Word).HasMaxLength(100).IsRequired();builder.Property(e => e.NormalizedWord).HasMaxLength(100).IsRequired();builder.Property(e => e.Category).HasConversion<string>().HasMaxLength(30);builder.Property(e => e.Severity).HasConversion<string>().HasMaxLength(10);builder.Property(e => e.Language).HasMaxLength(10);builder.HasIndex(e => e.NormalizedWord);}}
